impl RuntimeFilePermission {
    fn as_str(self) -> &'static str {
        match self {
            Self::Read => "read",
            Self::Write => "write",
            Self::Append => "append",
            Self::ReadWrite => "read/write",
            Self::WriteRead => "write/read",
            Self::AppendRead => "append/read",
        }
    }
}

#[derive(Debug)]
enum RuntimeOpenFile {
    Reader(BufReader<fs::File>),
    Writer(fs::File),
    ReadWriter(fs::File),
}

#[derive(Debug)]
struct RuntimeFileHandle {
    path: PathBuf,
    query_filename: String,
    permission: RuntimeFilePermission,
    permission_text: String,
    text_mode: bool,
    auto_flush: bool,
    machinefmt: BinaryMachineFormat,
    encoding: String,
    stream: RuntimeOpenFile,
    eof_indicator: bool,
    last_error_message: String,
    last_error_number: i32,
}

impl RuntimeFileHandle {
    fn normalize_text_mode_line(line: &str) -> String {
        if cfg!(windows) {
            line.replace("\r\n", "\n")
        } else {
            line.to_string()
        }
    }

    fn encode_text_mode_output(text: &str) -> String {
        if !cfg!(windows) {
            return text.to_string();
        }
        let mut encoded = String::with_capacity(text.len() + 8);
        let mut previous_was_cr = false;
        for ch in text.chars() {
            if ch == '\n' && !previous_was_cr {
                encoded.push('\r');
            }
            encoded.push(ch);
            previous_was_cr = ch == '\r';
        }
        encoded
    }

    fn read_line_stream<R: Read>(
        stream: &mut R,
        keep_newline: bool,
        text_mode: bool,
    ) -> Result<Option<String>, std::io::Error> {
        let mut bytes = Vec::new();
        let mut chunk = [0u8; 1];
        loop {
            match stream.read(&mut chunk)? {
                0 if bytes.is_empty() => return Ok(None),
                0 => break,
                _ => {
                    bytes.push(chunk[0]);
                    if chunk[0] == b'\n' {
                        break;
                    }
                }
            }
        }
        let mut line = String::from_utf8_lossy(&bytes).into_owned();
        if text_mode {
            line = Self::normalize_text_mode_line(&line);
        }
        if !keep_newline {
            if line.ends_with('\n') {
                line.pop();
            }
            if line.ends_with('\r') {
                line.pop();
            }
        }
        Ok(Some(line))
    }

    fn clear_error(&mut self) {
        self.last_error_message.clear();
        self.last_error_number = 0;
    }

    fn set_error(&mut self, message: impl Into<String>, number: i32) {
        self.last_error_message = message.into();
        self.last_error_number = number;
    }

    fn error_state(&self) -> (String, i32) {
        (self.last_error_message.clone(), self.last_error_number)
    }

    fn current_position(&mut self, builtin_name: &str) -> Result<u64, RuntimeError> {
        let path = self.path.display().to_string();
        match &mut self.stream {
            RuntimeOpenFile::Reader(reader) => reader.stream_position().map_err(|error| {
                self.set_error(error.to_string(), -1);
                RuntimeError::Unsupported(format!(
                    "{builtin_name} failed while querying `{path}`: {error}"
                ))
            }),
            RuntimeOpenFile::Writer(writer) => writer.stream_position().map_err(|error| {
                self.set_error(error.to_string(), -1);
                RuntimeError::Unsupported(format!(
                    "{builtin_name} failed while querying `{path}`: {error}"
                ))
            }),
            RuntimeOpenFile::ReadWriter(stream) => stream.stream_position().map_err(|error| {
                self.set_error(error.to_string(), -1);
                RuntimeError::Unsupported(format!(
                    "{builtin_name} failed while querying `{path}`: {error}"
                ))
            }),
        }
    }

    fn file_length(&mut self, builtin_name: &str) -> Result<u64, RuntimeError> {
        fs::metadata(&self.path)
            .map(|metadata| metadata.len())
            .map_err(|error| {
                self.set_error(error.to_string(), -1);
                RuntimeError::Unsupported(format!(
                    "{builtin_name} failed while querying `{}`: {error}",
                    self.path.display()
                ))
            })
    }

    fn set_position(&mut self, builtin_name: &str, position: u64) -> Result<(), RuntimeError> {
        let path = self.path.display().to_string();
        let result = match &mut self.stream {
            RuntimeOpenFile::Reader(reader) => reader.seek(SeekFrom::Start(position)),
            RuntimeOpenFile::Writer(writer) => writer.seek(SeekFrom::Start(position)),
            RuntimeOpenFile::ReadWriter(stream) => stream.seek(SeekFrom::Start(position)),
        };
        result
            .map(|_| {
                self.eof_indicator = false;
                self.clear_error();
            })
            .map_err(|error| {
                self.set_error(error.to_string(), -1);
                RuntimeError::Unsupported(format!(
                    "{builtin_name} failed while seeking `{path}`: {error}"
                ))
            })
    }

    fn query_ftell(&mut self) -> f64 {
        match self.current_position("ftell") {
            Ok(position) => position as f64,
            Err(_) => -1.0,
        }
    }

    fn query_feof(&self) -> f64 {
        if self.eof_indicator {
            1.0
        } else {
            0.0
        }
    }

    fn seek_offset(
        &mut self,
        offset: i64,
        origin: RuntimeFileSeekOrigin,
        builtin_name: &str,
    ) -> f64 {
        let base = match origin {
            RuntimeFileSeekOrigin::Beginning => 0i64,
            RuntimeFileSeekOrigin::Current => match self.current_position(builtin_name) {
                Ok(position) => position as i64,
                Err(_) => return -1.0,
            },
            RuntimeFileSeekOrigin::End => match self.file_length(builtin_name) {
                Ok(length) => length as i64,
                Err(_) => return -1.0,
            },
        };
        let Some(target) = base.checked_add(offset) else {
            self.set_error("Offset is bad - before beginning-of-file.", -1);
            return -1.0;
        };
        if target < 0 {
            self.set_error("Offset is bad - before beginning-of-file.", -1);
            return -1.0;
        }
        match self.set_position(builtin_name, target as u64) {
            Ok(()) => 0.0,
            Err(_) => -1.0,
        }
    }

    fn seek_relative(&mut self, builtin_name: &str, offset: i64) -> Result<bool, RuntimeError> {
        let path = self.path.display().to_string();
        let result = match &mut self.stream {
            RuntimeOpenFile::Reader(reader) => reader.seek(SeekFrom::Current(offset)),
            RuntimeOpenFile::Writer(writer) => writer.seek(SeekFrom::Current(offset)),
            RuntimeOpenFile::ReadWriter(stream) => stream.seek(SeekFrom::Current(offset)),
        };
        match result {
            Ok(_) => {
                self.eof_indicator = false;
                self.clear_error();
                Ok(true)
            }
            Err(error) => {
                self.set_error(error.to_string(), -1);
                let _ = builtin_name;
                let _ = path;
                Ok(false)
            }
        }
    }

    fn read_binary_chunk(
        &mut self,
        builtin_name: &str,
        bytes: &mut [u8],
    ) -> Result<bool, RuntimeError> {
        let path = self.path.display().to_string();
        let result = match &mut self.stream {
            RuntimeOpenFile::Reader(reader) => reader.read_exact(bytes),
            RuntimeOpenFile::ReadWriter(stream) => stream.read_exact(bytes),
            RuntimeOpenFile::Writer(_) => {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects a file opened for reading, found `{path}` opened with {} access",
                    self.permission.as_str()
                )))
            }
        };
        match result {
            Ok(()) => {
                self.eof_indicator = false;
                self.clear_error();
                Ok(true)
            }
            Err(error) if error.kind() == std::io::ErrorKind::UnexpectedEof => {
                self.eof_indicator = true;
                self.clear_error();
                Ok(false)
            }
            Err(error) => {
                self.eof_indicator = false;
                self.set_error(error.to_string(), -1);
                Ok(false)
            }
        }
    }

    fn write_binary_chunk(
        &mut self,
        builtin_name: &str,
        bytes: &[u8],
    ) -> Result<bool, RuntimeError> {
        let path = self.path.display().to_string();
        let result = match &mut self.stream {
            RuntimeOpenFile::Writer(writer) => writer.write_all(bytes).and_then(|_| {
                if self.auto_flush {
                    writer.flush()
                } else {
                    Ok(())
                }
            }),
            RuntimeOpenFile::ReadWriter(stream) => stream.write_all(bytes).and_then(|_| {
                if self.auto_flush {
                    stream.flush()
                } else {
                    Ok(())
                }
            }),
            RuntimeOpenFile::Reader(_) => {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects a file opened for writing, found `{path}` opened with {} access",
                    self.permission.as_str()
                )))
            }
        };
        match result {
            Ok(()) => {
                self.eof_indicator = false;
                self.clear_error();
                Ok(true)
            }
            Err(error) => {
                self.eof_indicator = false;
                self.set_error(error.to_string(), -1);
                Ok(false)
            }
        }
    }

    fn read_line(
        &mut self,
        builtin_name: &str,
        keep_newline: bool,
    ) -> Result<Option<String>, RuntimeError> {
        let path = self.path.display().to_string();
        let line = match &mut self.stream {
            RuntimeOpenFile::Reader(reader) => Self::read_line_stream(reader, keep_newline, self.text_mode),
            RuntimeOpenFile::ReadWriter(stream) => {
                Self::read_line_stream(stream, keep_newline, self.text_mode)
            }
            RuntimeOpenFile::Writer(_) => {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects a file opened for reading, found `{path}` opened with {} access",
                    self.permission.as_str()
                )))
            }
        };
        match line {
            Ok(None) => {
                self.eof_indicator = true;
                self.clear_error();
                Ok(None)
            }
            Ok(Some(line)) => {
                self.eof_indicator = false;
                self.clear_error();
                Ok(Some(line))
            }
            Err(error) => {
                self.set_error(error.to_string(), -1);
                Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} failed while reading `{path}`: {error}"
                )))
            }
        }
    }

    fn write_text(&mut self, builtin_name: &str, text: &str) -> Result<(), RuntimeError> {
        let path = self.path.display().to_string();
        let rendered = if self.text_mode {
            Self::encode_text_mode_output(text)
        } else {
            text.to_string()
        };
        match &mut self.stream {
            RuntimeOpenFile::Writer(writer) => writer
                .write_all(rendered.as_bytes())
                .and_then(|_| {
                    if self.auto_flush {
                        writer.flush()
                    } else {
                        Ok(())
                    }
                })
                .map(|_| {
                    self.eof_indicator = false;
                    self.clear_error();
                })
                .map_err(|error| {
                    self.set_error(error.to_string(), -1);
                    RuntimeError::Unsupported(format!(
                        "{builtin_name} failed while writing `{path}`: {error}"
                    ))
                }),
            RuntimeOpenFile::ReadWriter(stream) => stream
                .write_all(rendered.as_bytes())
                .and_then(|_| {
                    if self.auto_flush {
                        stream.flush()
                    } else {
                        Ok(())
                    }
                })
                .map(|_| {
                    self.eof_indicator = false;
                    self.clear_error();
                })
                .map_err(|error| {
                    self.set_error(error.to_string(), -1);
                    RuntimeError::Unsupported(format!(
                        "{builtin_name} failed while writing `{path}`: {error}"
                    ))
                }),
            RuntimeOpenFile::Reader(_) => Err(RuntimeError::TypeError(format!(
                "{builtin_name} currently expects a file opened for writing, found `{path}` opened with {} access",
                self.permission.as_str()
            ))),
        }
    }
}

#[derive(Clone)]
struct Frame<'a> {
    cells: HashMap<BindingId, Cell>,
    names: BTreeMap<String, BindingId>,
    declared_names: BTreeMap<String, BindingId>,
    global_names: BTreeSet<String>,
    persistent_names: BTreeSet<String>,
    visible_functions: BTreeMap<String, &'a HirFunction>,
}

#[derive(Debug)]
struct SharedRuntimeState {
    globals: HashMap<String, Cell>,
    persistents: HashMap<PersistentKey, Cell>,
    current_directory: Option<PathBuf>,
    open_files: HashMap<i32, RuntimeFileHandle>,
    next_file_id: i32,
    default_user_path_root: Option<PathBuf>,
    user_path_root: Option<PathBuf>,
    default_search_path_roots: Vec<PathBuf>,
    search_path_roots: Vec<PathBuf>,
    bundled_modules: HashMap<PathBuf, BytecodeModule>,
    bundled_modules_by_id: HashMap<String, BytecodeModule>,
    bundled_module_source_paths: HashMap<String, String>,
    loaded_functions: BTreeMap<String, LoadedFunctionInfo>,
    loaded_classes: BTreeSet<String>,
    last_warning: Option<WarningState>,
    last_tic_seconds: Option<f64>,
    next_dynamic_binding_id: u32,
    pause_enabled: bool,
    warnings_enabled: bool,
    warning_overrides: HashMap<String, bool>,
    checked_out_licenses: BTreeSet<String>,
    license_test_overrides: HashMap<String, bool>,
    display_format: DisplayFormatState,
    graphics: GraphicsState,
    pending_host_close_events: BTreeSet<u32>,
    pending_host_resize_events: BTreeSet<u32>,
    active_close_callbacks: BTreeSet<u32>,
    active_resize_callbacks: BTreeSet<u32>,
    displayed_outputs: Vec<DisplayedOutput>,
    figure_backend: Option<FigureBackendState>,
}

impl Default for SharedRuntimeState {
    fn default() -> Self {
        let default_user_path_root = default_runtime_user_path();
        let default_search_path_roots = matlab_resolver::search_roots_from_env("MATC_PATH");
        let search_path_roots = search_path_roots_with_user_path(
            default_user_path_root.as_ref(),
            &default_search_path_roots,
        );
        Self {
            globals: HashMap::new(),
            persistents: HashMap::new(),
            current_directory: None,
            open_files: HashMap::new(),
            next_file_id: 3,
            default_user_path_root: default_user_path_root.clone(),
            user_path_root: default_user_path_root,
            default_search_path_roots,
            search_path_roots,
            bundled_modules: HashMap::new(),
            bundled_modules_by_id: HashMap::new(),
            bundled_module_source_paths: HashMap::new(),
            loaded_functions: BTreeMap::new(),
            loaded_classes: BTreeSet::new(),
            last_warning: None,
            last_tic_seconds: None,
            next_dynamic_binding_id: 1_000_000,
            pause_enabled: true,
            warnings_enabled: true,
            warning_overrides: HashMap::new(),
            checked_out_licenses: BTreeSet::from(["matlab".to_string()]),
            license_test_overrides: HashMap::new(),
            display_format: DisplayFormatState::default(),
            graphics: GraphicsState::default(),
            pending_host_close_events: BTreeSet::new(),
            pending_host_resize_events: BTreeSet::new(),
            active_close_callbacks: BTreeSet::new(),
            active_resize_callbacks: BTreeSet::new(),
            displayed_outputs: Vec::new(),
            figure_backend: figure_backend_from_env(),
        }
    }
}

fn install_bundled_modules(
    shared_state: &Rc<RefCell<SharedRuntimeState>>,
    modules: &[PackagedBytecodeModule],
) {
    if modules.is_empty() {
        return;
    }
    let mut state = shared_state.borrow_mut();
    for module in modules {
        let path = PathBuf::from(&module.source_path);
        state
            .bundled_modules
            .insert(path.clone(), module.module.clone());
        state
            .bundled_modules_by_id
            .insert(module.module_id.clone(), module.module.clone());
        state
            .bundled_module_source_paths
            .insert(module.module_id.clone(), module.source_path.clone());
        record_loaded_bytecode_module(&mut state, &module.module, Some(&path));
    }
}

fn bundled_module_registries(
    shared_state: &Rc<RefCell<SharedRuntimeState>>,
) -> (
    Rc<HashMap<PathBuf, BytecodeModule>>,
    Rc<HashMap<String, BytecodeModule>>,
) {
    let state = shared_state.borrow();
    (
        Rc::new(state.bundled_modules.clone()),
        Rc::new(state.bundled_modules_by_id.clone()),
    )
}

fn snapshot_bundle_modules(
    shared_state: &Rc<RefCell<SharedRuntimeState>>,
) -> Vec<PackagedBytecodeModule> {
    let state = shared_state.borrow();
    let mut module_ids = state
        .bundled_modules_by_id
        .keys()
        .cloned()
        .collect::<Vec<_>>();
    module_ids.sort();
    module_ids
        .into_iter()
        .filter_map(|module_id| {
            let module = state.bundled_modules_by_id.get(&module_id)?.clone();
            let source_path = state
                .bundled_module_source_paths
                .get(&module_id)
                .cloned()
                .unwrap_or_default();
            Some(PackagedBytecodeModule {
                module_id,
                source_path,
                module,
            })
        })
        .collect()
}

fn collect_root_scoped_bundle_paths_from_value(
    value: &Value,
    state: &SharedRuntimeState,
    paths: &mut BTreeSet<PathBuf>,
) {
    match value {
        Value::FunctionHandle(handle) => {
            if let FunctionHandleTarget::Named(name) = &handle.target {
                if let Some((path, _)) = parse_scoped_function_handle_name(name) {
                    let already_packaged = state
                        .bundled_module_source_paths
                        .values()
                        .any(|source| PathBuf::from(source) == path);
                    if state.bundled_modules.contains_key(&path) && !already_packaged {
                        paths.insert(path);
                    }
                }
            }
        }
        Value::Matrix(matrix) => {
            for element in matrix.elements() {
                collect_root_scoped_bundle_paths_from_value(element, state, paths);
            }
        }
        Value::Cell(cell) => {
            for element in cell.elements() {
                collect_root_scoped_bundle_paths_from_value(element, state, paths);
            }
        }
        Value::Struct(struct_value) => {
            for value in struct_value.fields.values() {
                collect_root_scoped_bundle_paths_from_value(value, state, paths);
            }
        }
        Value::Object(object) => {
            for value in object.properties().fields.values() {
                collect_root_scoped_bundle_paths_from_value(value, state, paths);
            }
        }
        _ => {}
    }
}

fn snapshot_bundle_modules_for_workspace(
    shared_state: &Rc<RefCell<SharedRuntimeState>>,
    workspace: &Workspace,
) -> Vec<PackagedBytecodeModule> {
    let mut modules = snapshot_bundle_modules(shared_state);
    let state = shared_state.borrow();
    let mut root_paths = BTreeSet::new();
    for value in workspace.values() {
        collect_root_scoped_bundle_paths_from_value(value, &state, &mut root_paths);
    }
    for path in root_paths {
        if let Some(module) = state.bundled_modules.get(&path) {
            modules.push(PackagedBytecodeModule {
                module_id: format!("root::{}", path.display()),
                source_path: path.display().to_string(),
                module: module.clone(),
            });
        }
    }
    modules
}

fn encode_snapshot_bundle_modules(
    modules: &[PackagedBytecodeModule],
) -> Vec<WorkspaceSnapshotBundleModule> {
    modules
        .iter()
        .map(|module| WorkspaceSnapshotBundleModule {
            module_id: module.module_id.clone(),
            source_path: module.source_path.clone(),
            encoded_module: encode_bytecode_module(&module.module),
        })
        .collect()
}

fn decode_snapshot_bundle_modules(
    modules: &[WorkspaceSnapshotBundleModule],
) -> Result<Vec<PackagedBytecodeModule>, RuntimeError> {
    modules
        .iter()
        .map(|module| {
            decode_bytecode_module(&module.encoded_module)
                .map(|decoded| PackagedBytecodeModule {
                    module_id: module.module_id.clone(),
                    source_path: module.source_path.clone(),
                    module: decoded,
                })
                .map_err(|error| {
                    RuntimeError::Unsupported(format!(
                        "failed to decode embedded bundle module `{}` from workspace snapshot: {error}",
                        module.module_id
                    ))
                })
        })
        .collect()
}

fn object_method_target_is_bundle_backed(
    target: &ObjectMethodTarget,
    state: &SharedRuntimeState,
) -> bool {
    match target {
        ObjectMethodTarget::BundleModule(_) => true,
        ObjectMethodTarget::Path(path) => state.bundled_modules.contains_key(path),
    }
}

fn function_handle_target_is_bundle_backed(
    target: &FunctionHandleTarget,
    state: &SharedRuntimeState,
) -> bool {
    match target {
        FunctionHandleTarget::BundleModule(_) => true,
        FunctionHandleTarget::ResolvedPath(path) => state.bundled_modules.contains_key(path),
        FunctionHandleTarget::BoundMethod { receiver, .. } => {
            value_contains_bundle_backed_modules(receiver, state)
        }
        FunctionHandleTarget::Named(name) => parse_scoped_function_handle_name(name)
            .is_some_and(|(path, _)| state.bundled_modules.contains_key(&path)),
    }
}

fn install_root_bundled_module(
    shared_state: &Rc<RefCell<SharedRuntimeState>>,
    source_path: &str,
    module: &BytecodeModule,
) {
    let mut state = shared_state.borrow_mut();
    state
        .bundled_modules
        .insert(PathBuf::from(source_path), module.clone());
    record_loaded_bytecode_module(&mut state, module, Some(Path::new(source_path)));
}

fn record_loaded_hir_module(
    shared_state: &Rc<RefCell<SharedRuntimeState>>,
    module: &HirModule,
    source_path: Option<&Path>,
) {
    let mut state = shared_state.borrow_mut();
    record_loaded_hir_module_state(&mut state, module, source_path);
}

fn record_loaded_hir_module_state(
    state: &mut SharedRuntimeState,
    module: &HirModule,
    source_path: Option<&Path>,
) {
    if module.kind == CompilationUnitKind::FunctionFile {
        if let Some(path) = source_path {
            record_loaded_function_path(state, path);
        }
    }
    for class in &module.classes {
        state.loaded_classes.insert(qualified_object_class_name(
            &class.name,
            class.package.as_deref(),
        ));
    }
}

fn record_loaded_bytecode_module(
    state: &mut SharedRuntimeState,
    module: &BytecodeModule,
    source_path: Option<&Path>,
) {
    if module.unit_kind == "FunctionFile" {
        if let Some(path) = source_path {
            record_loaded_function_path(state, path);
        }
    }
    for class in &module.classes {
        state.loaded_classes.insert(qualified_object_class_name(
            &class.name,
            class.package.as_deref(),
        ));
    }
}

fn record_loaded_function_path(state: &mut SharedRuntimeState, path: &Path) {
    let short_name = loaded_function_name_from_path(path);
    let complete_name = path.display().to_string();
    state.loaded_functions.insert(
        complete_name.to_ascii_lowercase(),
        LoadedFunctionInfo {
            short_name,
            complete_name,
        },
    );
}

fn loaded_function_name_from_path(path: &Path) -> String {
    let package_prefix = package_segments_from_path(path);
    let stem = path
        .file_stem()
        .and_then(|stem| stem.to_str())
        .unwrap_or_default()
        .to_string();
    let parent_class = path
        .parent()
        .and_then(|parent| parent.file_name())
        .and_then(|name| name.to_str())
        .and_then(|name| name.strip_prefix('@'))
        .map(ToOwned::to_owned);
    let base = match parent_class {
        Some(class_name) if !stem.eq_ignore_ascii_case(&class_name) => {
            format!("{class_name}.{stem}")
        }
        Some(class_name) => class_name,
        None => stem,
    };
    if package_prefix.is_empty() {
        base
    } else {
        format!("{package_prefix}.{base}")
    }
}

fn package_segments_from_path(path: &Path) -> String {
    let mut segments = path
        .ancestors()
        .skip(1)
        .filter_map(|ancestor| {
            ancestor
                .file_name()
                .and_then(|name| name.to_str())
                .and_then(|name| name.strip_prefix('+'))
                .map(ToOwned::to_owned)
        })
        .collect::<Vec<_>>();
    segments.reverse();
    segments.join(".")
}

fn value_contains_bundle_backed_modules(value: &Value, state: &SharedRuntimeState) -> bool {
    match value {
        Value::FunctionHandle(handle) => {
            function_handle_target_is_bundle_backed(&handle.target, state)
        }
        Value::Object(object) => {
            object
                .class
                .module_target
                .as_ref()
                .is_some_and(|target| object_method_target_is_bundle_backed(target, state))
                || object
                    .class
                    .source_path
                    .as_ref()
                    .is_some_and(|path| state.bundled_modules.contains_key(path))
                || object
                    .class
                    .external_methods
                    .values()
                    .any(|target| object_method_target_is_bundle_backed(target, state))
                || object
                    .properties()
                    .fields
                    .values()
                    .any(|value| value_contains_bundle_backed_modules(value, state))
        }
        Value::Matrix(matrix) => matrix
            .iter()
            .any(|value| value_contains_bundle_backed_modules(value, state)),
        Value::Cell(cell) => cell
            .iter()
            .any(|value| value_contains_bundle_backed_modules(value, state)),
        Value::Struct(struct_value) => struct_value
            .fields
            .values()
            .any(|value| value_contains_bundle_backed_modules(value, state)),
        _ => false,
    }
}

fn workspace_contains_bundle_backed_modules(
    shared_state: &Rc<RefCell<SharedRuntimeState>>,
    workspace: &Workspace,
) -> bool {
    let state = shared_state.borrow();
    workspace
        .values()
        .any(|value| value_contains_bundle_backed_modules(value, &state))
}

