#[derive(Debug, Clone)]
struct LoadedClassModule {
    module: HirModule,
    class: matlab_ir::HirClass,
    source_path: PathBuf,
}

fn load_class_module_from_path(path: &Path) -> Result<LoadedClassModule, RuntimeError> {
    let source = fs::read_to_string(path).map_err(|error| {
        RuntimeError::Unsupported(format!(
            "failed to read class definition `{}`: {error}",
            path.display()
        ))
    })?;
    let parsed = parse_source(&source, SourceFileId(1), ParseMode::AutoDetect);
    if parsed.has_errors() {
        return Err(RuntimeError::Unsupported(format!(
            "failed to parse class definition `{}`: {}",
            path.display(),
            format_frontend_diagnostics(&parsed.diagnostics)
        )));
    }
    let unit = parsed.unit.ok_or_else(|| {
        RuntimeError::Unsupported(format!(
            "parser produced no compilation unit for class definition `{}`",
            path.display()
        ))
    })?;
    if unit.kind != CompilationUnitKind::ClassFile {
        return Err(RuntimeError::Unsupported(format!(
            "`{}` is not a class definition file",
            path.display()
        )));
    }
    let context =
        ResolverContext::from_source_file(path.to_path_buf()).with_env_search_roots("MATC_PATH");
    let analysis = analyze_compilation_unit_with_context(&unit, &context);
    if analysis.has_errors() {
        return Err(RuntimeError::Unsupported(format!(
            "failed to analyze class definition `{}`: {}",
            path.display(),
            format_semantic_diagnostics(&analysis.diagnostics)
        )));
    }
    let hir = lower_to_hir(&unit, &analysis);
    let class = hir.classes.first().cloned().ok_or_else(|| {
        RuntimeError::Unsupported(format!(
            "class definition `{}` did not lower class metadata",
            path.display()
        ))
    })?;
    Ok(LoadedClassModule {
        module: hir,
        class,
        source_path: path.to_path_buf(),
    })
}

fn path_resolution_is_class(kind: matlab_semantics::symbols::PathResolutionKind) -> bool {
    matches!(
        kind,
        matlab_semantics::symbols::PathResolutionKind::ClassCurrentDirectory
            | matlab_semantics::symbols::PathResolutionKind::ClassSearchPath
            | matlab_semantics::symbols::PathResolutionKind::ClassPackageDirectory
            | matlab_semantics::symbols::PathResolutionKind::ClassFolderCurrentDirectory
            | matlab_semantics::symbols::PathResolutionKind::ClassFolderSearchPath
            | matlab_semantics::symbols::PathResolutionKind::ClassFolderPackageDirectory
    )
}

fn object_has_method(object: &ObjectValue, method_name: &str) -> bool {
    object.class.inline_methods.contains(method_name)
        || object.class.external_methods.contains_key(method_name)
}

fn object_array_class_metadata(matrix: &MatrixValue) -> Option<ObjectClassMetadata> {
    let Value::Object(first_object) = matrix.elements.first()? else {
        return None;
    };
    matrix
        .iter()
        .all(|value| {
            matches!(
                value,
                Value::Object(object)
                    if object
                        .class
                        .qualified_name()
                        .eq_ignore_ascii_case(&first_object.class.qualified_name())
            )
        })
        .then(|| first_object.class.clone())
}

fn receiver_class_metadata(value: &Value) -> Option<ObjectClassMetadata> {
    match value {
        Value::Object(object) => Some(object.class.clone()),
        Value::Matrix(matrix) => object_array_class_metadata(matrix),
        _ => None,
    }
}

fn value_has_object_method(value: &Value, method_name: &str) -> bool {
    receiver_class_metadata(value).is_some_and(|class| {
        class.inline_methods.contains(method_name)
            || class.external_methods.contains_key(method_name)
    })
}

fn field_resolves_to_object_method(value: &Value, field: &str) -> bool {
    match value {
        Value::Object(object) => {
            object.property_value(field).is_none() && object_has_method(object, field)
        }
        Value::Matrix(matrix) if matrix_is_object_array(matrix) => {
            let Value::Object(first_object) = &matrix.elements[0] else {
                unreachable!("matrix_is_object_array checked every element");
            };
            first_object.property_value(field).is_none() && value_has_object_method(value, field)
        }
        _ => false,
    }
}

fn push_class_access_context(class_name: Option<String>) {
    CLASS_ACCESS_CONTEXT.with(|stack| stack.borrow_mut().push(class_name));
}

fn pop_class_access_context() {
    CLASS_ACCESS_CONTEXT.with(|stack| {
        stack.borrow_mut().pop();
    });
}

fn current_class_access_context() -> Option<String> {
    CLASS_ACCESS_CONTEXT.with(|stack| stack.borrow().last().cloned().flatten())
}

fn private_property_access_allowed(class: &ObjectClassMetadata, property: &str) -> bool {
    class.private_property_owner(property).is_none_or(|owner| {
        current_class_access_context()
            .as_deref()
            .is_some_and(|current| current.eq_ignore_ascii_case(&owner))
    })
}

fn private_instance_method_access_allowed(class: &ObjectClassMetadata, method: &str) -> bool {
    class
        .private_instance_method_owner(method)
        .is_none_or(|owner| {
            current_class_access_context()
                .as_deref()
                .is_some_and(|current| current.eq_ignore_ascii_case(&owner))
        })
}

fn private_static_method_access_allowed(
    qualified_class_name: &str,
    private_methods: &BTreeSet<String>,
    method: &str,
) -> bool {
    !private_methods.contains(method)
        || current_class_access_context()
            .as_deref()
            .is_some_and(|current| current.eq_ignore_ascii_case(qualified_class_name))
}

fn class_has_static_method(class: &matlab_ir::HirClass, method_name: &str) -> bool {
    class
        .static_inline_methods
        .iter()
        .any(|name| name == method_name)
}

fn private_property_owner_name(class: &ObjectClassMetadata, property: &str) -> String {
    class
        .private_property_owner(property)
        .unwrap_or_else(|| class.qualified_name())
}

fn private_instance_method_owner_name(class: &ObjectClassMetadata, method: &str) -> String {
    class
        .private_instance_method_owner(method)
        .unwrap_or_else(|| class.qualified_name())
}

fn resolved_path_static_method_name<'a>(path: &Path, display_name: &'a str) -> Option<&'a str> {
    let (_, method_name) = display_name.rsplit_once('.')?;
    let class_name = path.file_stem()?.to_str()?;
    (class_name != method_name).then_some(method_name)
}

fn source_path_from_module_identity(module_identity: &str) -> Option<PathBuf> {
    (!module_identity.starts_with('<')).then(|| PathBuf::from(module_identity))
}

fn normalize_runtime_path(path: PathBuf) -> PathBuf {
    #[cfg(windows)]
    {
        let text = path.to_string_lossy();
        if let Some(stripped) = text.strip_prefix(r"\\?\UNC\") {
            return PathBuf::from(format!(r"\\{stripped}"));
        }
        if let Some(stripped) = text.strip_prefix(r"\\?\") {
            return PathBuf::from(stripped);
        }
    }
    path
}

fn default_runtime_current_directory(resolution_source_path: Option<&Path>) -> PathBuf {
    normalize_runtime_path(
        resolution_source_path
            .and_then(|path| path.parent())
            .filter(|path| !path.as_os_str().is_empty())
            .map(Path::to_path_buf)
            .or_else(|| env::current_dir().ok())
            .unwrap_or_else(|| PathBuf::from(".")),
    )
}

fn default_runtime_user_path() -> Option<PathBuf> {
    #[cfg(windows)]
    let home = env::var_os("USERPROFILE").map(PathBuf::from).or_else(|| {
        let drive = env::var_os("HOMEDRIVE")?;
        let path = env::var_os("HOMEPATH")?;
        let mut home = PathBuf::from(drive);
        home.push(path);
        Some(home)
    });
    #[cfg(not(windows))]
    let home = env::var_os("HOME").map(PathBuf::from);

    home.map(|home| normalize_runtime_path(home.join("Documents").join("MATLAB")))
}

fn runtime_matlab_root() -> PathBuf {
    Path::new(env!("CARGO_MANIFEST_DIR"))
        .ancestors()
        .nth(2)
        .map(Path::to_path_buf)
        .unwrap_or_else(|| PathBuf::from("."))
}

fn runtime_toolbox_root() -> PathBuf {
    runtime_matlab_root().join("toolbox")
}

