fn resolve_named_callable_path(
    shared_state: &Rc<RefCell<SharedRuntimeState>>,
    resolution_source_path: Option<&Path>,
    name: &str,
) -> Option<PathBuf> {
    let context = resolution_context_with_env(shared_state, resolution_source_path);
    match resolve_callable(name, &context)? {
        ResolvedCallable::Function(resolved) => Some(resolved.path),
        ResolvedCallable::Class(resolved) => Some(resolved.path),
    }
}

fn is_missing_static_method_error(error: &RuntimeError, method_name: &str) -> bool {
    matches!(
        error,
        RuntimeError::MissingVariable(message)
            if message.contains(&format!("static method `{method_name}` is not defined"))
    )
}

fn resolve_superclass_path(
    source_path: &Path,
    superclass_name: &str,
) -> Result<PathBuf, RuntimeError> {
    let context = ResolverContext::from_source_file(source_path.to_path_buf())
        .with_env_search_roots("MATC_PATH");
    resolve_class_definition(superclass_name, &context)
        .map(|resolved| resolved.path)
        .ok_or_else(|| {
            RuntimeError::MissingVariable(format!(
                "superclass `{superclass_name}` is not available from `{}`",
                source_path.display()
            ))
        })
}

fn object_matches_declaring_class_or_subclass(
    object: &ObjectValue,
    declaring_class_name: &str,
) -> bool {
    object
        .class
        .qualified_name()
        .eq_ignore_ascii_case(declaring_class_name)
        || object
            .class
            .ancestor_class_names
            .iter()
            .any(|name| name.eq_ignore_ascii_case(declaring_class_name))
}

fn super_constructor_matches_declaring_class(
    object: &ObjectValue,
    declaring_class_name: &str,
    declaring_superclass_name: Option<&str>,
    target_class_name: &str,
) -> bool {
    object_matches_declaring_class_or_subclass(object, declaring_class_name)
        && declaring_superclass_name
            .is_some_and(|name| name.eq_ignore_ascii_case(target_class_name))
}

fn bound_method_value(receiver: &Value, method_name: &str) -> Value {
    let class = receiver_class_metadata(receiver).expect("bound method receiver class metadata");
    Value::FunctionHandle(FunctionHandleValue {
        display_name: format!("{}.{}", class.qualified_name(), method_name),
        target: FunctionHandleTarget::BoundMethod {
            class_name: class.class_name,
            package: class.package,
            method_name: method_name.to_string(),
            receiver: Box::new(receiver.clone()),
        },
    })
}

fn resolve_dotted_receiver_from_root(
    mut receiver: Value,
    segments_after_root: &[&str],
) -> Result<Value, RuntimeError> {
    for field in segments_after_root {
        receiver = read_field_value(&receiver, field)?;
    }
    Ok(receiver)
}

fn try_build_bound_method_handle_from_dotted_name(
    receiver: Value,
    segments: &[&str],
) -> Result<Option<Value>, RuntimeError> {
    if segments.len() < 2 {
        return Ok(None);
    }

    let current = resolve_dotted_receiver_from_root(receiver, &segments[1..segments.len() - 1])?;

    let method_name = segments[segments.len() - 1];
    if value_has_object_method(&current, method_name) {
        Ok(Some(bound_method_value(&current, method_name)))
    } else {
        Ok(None)
    }
}

pub fn execute_script(module: &HirModule) -> Result<ExecutionResult, RuntimeError> {
    if module.kind != CompilationUnitKind::Script {
        return Err(RuntimeError::Unsupported(
            "execute_script expects a script compilation unit".to_string(),
        ));
    }

    let mut interpreter = Interpreter::new(module);
    interpreter.execute_script()
}

pub fn execute_script_with_identity(
    module: &HirModule,
    module_identity: String,
    source_path: Option<PathBuf>,
) -> Result<ExecutionResult, RuntimeError> {
    if module.kind != CompilationUnitKind::Script {
        return Err(RuntimeError::Unsupported(
            "execute_script expects a script compilation unit".to_string(),
        ));
    }

    let mut interpreter = Interpreter::with_shared_state(
        module,
        module_identity.clone(),
        Rc::new(RefCell::new(SharedRuntimeState::default())),
        Vec::new(),
    );
    interpreter.resolution_source_path =
        source_path.or_else(|| source_path_from_module_identity(&module_identity));
    interpreter.execute_script()
}

pub fn execute_function_file(
    module: &HirModule,
    args: &[Value],
) -> Result<ExecutionResult, RuntimeError> {
    if module.kind != CompilationUnitKind::FunctionFile {
        return Err(RuntimeError::Unsupported(
            "execute_function_file expects a function-file compilation unit".to_string(),
        ));
    }

    let mut interpreter = Interpreter::new(module);
    interpreter.execute_function_file(args)
}

pub fn execute_function_file_with_identity(
    module: &HirModule,
    args: &[Value],
    module_identity: String,
    source_path: Option<PathBuf>,
) -> Result<ExecutionResult, RuntimeError> {
    if module.kind != CompilationUnitKind::FunctionFile {
        return Err(RuntimeError::Unsupported(
            "execute_function_file expects a function-file compilation unit".to_string(),
        ));
    }

    let mut interpreter = Interpreter::with_shared_state(
        module,
        module_identity.clone(),
        Rc::new(RefCell::new(SharedRuntimeState::default())),
        Vec::new(),
    );
    interpreter.resolution_source_path =
        source_path.or_else(|| source_path_from_module_identity(&module_identity));
    interpreter.execute_function_file(args)
}

pub fn render_execution_result(result: &ExecutionResult) -> String {
    let mut filtered = result.workspace.clone();
    filtered.remove("ans");
    render_workspace_with_format(&filtered, result.display_format)
}

pub fn render_matlab_execution_result(result: &ExecutionResult) -> String {
    let mut out = String::new();
    for (index, displayed) in result.displayed_outputs.iter().enumerate() {
        match displayed {
            DisplayedOutput::NamedValue { name, value } => {
                if index > 0 && matlab_named_output_uses_blank_separator(result.display_format) {
                    out.push('\n');
                }
                render_named_value_with_format(&mut out, "", name, value, result.display_format);
            }
            DisplayedOutput::Text {
                text,
                ensure_trailing_newline,
            } => {
                out.push_str(text);
                if *ensure_trailing_newline && !text.ends_with('\n') {
                    out.push('\n');
                }
            }
        }
    }
    out
}

fn first_statement_value<'a>(
    interpreter: &mut Interpreter<'a>,
    frame: &mut Frame<'a>,
    expression: &HirExpression,
) -> Result<Option<Value>, RuntimeError> {
    match expression {
        HirExpression::Call { target, args }
            if call_target_suppresses_ans_in_statement(target, args.len()) =>
        {
            interpreter.execute_statement_builtin_call(frame, target, args)?;
            Ok(None)
        }
        HirExpression::Call { target, args } => Ok(interpreter
            .evaluate_call_outputs(frame, target, args, Some(1))?
            .into_iter()
            .next()),
        _ => Ok(Some(interpreter.evaluate_expression(frame, expression)?)),
    }
}

fn call_target_suppresses_ans_in_statement(target: &HirCallTarget, arg_count: usize) -> bool {
    let HirCallTarget::Callable(reference) = target else {
        return false;
    };
    if reference.binding_id.is_some() {
        return false;
    }
    if matches!(
        reference.final_resolution,
        Some(FinalReferenceResolution::ResolvedPath { .. })
    ) {
        return false;
    }
    statement_builtin_suppresses_ans(reference.name.as_str(), arg_count)
}

