    fn matlab_render_displays_assignments_and_expression_ans() {
        let result = execute_script_source("a = 1\n1 + 2\n");
        assert_eq!(
            render_matlab_execution_result(&result),
            "a = 1\n\nans = 3\n"
        );
    }

