    #[test]
    fn linear_matrix_deletion_flattens_nonvector_inputs_in_matlab_order() {
        let result = execute_script_source(
            "a = [1 2; 3 4];\n\
             a([1 3]) = [];\n\
             out = a;\n\
             b = cat(3, [1 2; 3 4], [5 6; 7 8]);\n\
             b([1 3 7]) = [];\n\
             out_nd = b;\n\
             clear a b;\n",
        );
        assert_eq!(
            render_execution_result(&result),
            "workspace\n  out = [3 ; 4]\n  out_nd = [3 ; 4 ; 5 ; 7 ; 8]\n"
        );
    }

