    #[test]
    fn matrix_literals_concatenate_matrix_valued_expressions() {
        let source = "x = [1 2; 3 4];\n\
                      h = [x x];\n\
                      v = [x; x];\n";

        let interpreted = execute_script_source(source);
        let Value::Matrix(h) = interpreted.workspace.get("h").expect("horizontal result") else {
            panic!("expected matrix literal result");
        };
        assert_eq!(h.rows, 2);
        assert_eq!(h.cols, 4);
        assert_eq!(
            h.elements,
            vec![
                Value::Scalar(1.0),
                Value::Scalar(2.0),
                Value::Scalar(1.0),
                Value::Scalar(2.0),
                Value::Scalar(3.0),
                Value::Scalar(4.0),
                Value::Scalar(3.0),
                Value::Scalar(4.0),
            ]
        );
        let Value::Matrix(v) = interpreted.workspace.get("v").expect("vertical result") else {
            panic!("expected matrix literal result");
        };
        assert_eq!(v.rows, 4);
        assert_eq!(v.cols, 2);
        assert_eq!(
            v.elements,
            vec![
                Value::Scalar(1.0),
                Value::Scalar(2.0),
                Value::Scalar(3.0),
                Value::Scalar(4.0),
                Value::Scalar(1.0),
                Value::Scalar(2.0),
                Value::Scalar(3.0),
                Value::Scalar(4.0),
            ]
        );

        let bytecode = execute_script_source_bytecode(source);
        let Value::Matrix(h) = bytecode
            .workspace
            .get("h")
            .expect("bytecode horizontal result")
        else {
            panic!("expected matrix literal result");
        };
        assert_eq!(h.rows, 2);
        assert_eq!(h.cols, 4);
        let Value::Matrix(v) = bytecode
            .workspace
            .get("v")
            .expect("bytecode vertical result")
        else {
            panic!("expected matrix literal result");
        };
        assert_eq!(v.rows, 4);
        assert_eq!(v.cols, 2);
    }

